1	const PROCESSING_FEE = 5;
2	const COMPONENT_PREMIUM = 25;
3	const BLOCK_SIZE = 3;
4	const BLOCK_PREMIUM = 60;
5	const COMPONENT_TYPES = ["rune", "moonstone"];
6	
7	const isComponent = (item: any): boolean => COMPONENT_TYPES.includes(item.type);
8	
9	const CURSED_SURCHARGE_RATE = 0.5;
10	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
11	const HIGH_ENCHANTMENT_THRESHOLD = 5;
12	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
13	const LOYALTY_DISCOUNT_RATE = 0.2;
14	const LOYALTY_YEARS_THRESHOLD = 2;
15	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
16	
17	const BASE_PREMIUMS: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	};
23	
24	const INSURANCE_VALUES: Record<string, number> = {
25	  sword: 1000,
26	  amulet: 600,
27	  staff: 800,
28	  potion: 400,
29	};
30	
31	const COMPONENT_INSURANCE_VALUE = 250;
32	const DEDUCTIBLE = 100;
33	
34	const computeItemSurcharges = (item: any, base: number): number => {
35	  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
36	  const enchantmentSurcharge = item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
37	  return cursedSurcharge + enchantmentSurcharge;
38	};
39	
40	const computeComponentPremium = (count: number): number =>
41	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
42	
43	const computeItemsPremium = (items: any[]): { itemsTotal: number; policyBase: number } => {
44	  const componentCounts: Record<string, number> = {};
45	  let itemsTotal = 0;
46	  let policyBase = 0;
47	  for (const item of items) {
48	    if (isComponent(item)) {
49	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
50	    } else {
51	      if (!(item.type in BASE_PREMIUMS)) throw new Error(`Unknown item type: ${item.type}`);
52	      const base = BASE_PREMIUMS[item.type];
53	      policyBase += base;
54	      itemsTotal += base + computeItemSurcharges(item, base);
55	    }
56	  }
57	  for (const count of Object.values(componentCounts)) {
58	    const premium = computeComponentPremium(count);
59	    policyBase += premium;
60	    itemsTotal += premium;
61	  }
62	  return { itemsTotal, policyBase };
63	};
64	
65	const computeInsuranceSum = (items: any[]): number =>
66	  items.reduce((sum: number, item: any) =>
67	    sum + (isComponent(item) ? COMPONENT_INSURANCE_VALUE : INSURANCE_VALUES[item.type]), 0);
68	
69	const computePolicyModifiers = (policyBase: number, yearsWithMHPCO: number, isFollowUp: boolean): number => {
70	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
71	  const loyaltyDiscount = yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
72	  const followUpDiscount = isFollowUp ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
73	  return firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount;
74	};
75	
76	const processQuote = (step: any, yearsWithMHPCO: number, isFollowUp: boolean, policies: any[]): any => {
77	  const { itemsTotal, policyBase } = computeItemsPremium(step.items);
78	  const policyModifiers = computePolicyModifiers(policyBase, yearsWithMHPCO, isFollowUp);
79	  const insuranceSum = computeInsuranceSum(step.items);
80	  policies.push({ items: step.items, insuranceSum, remainingCap: insuranceSum * 2 });
81	  return { premium: Math.ceil(itemsTotal + policyModifiers + PROCESSING_FEE) };
82	};
83	
84	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
85	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
86	
87	const processClaim = (step: any, policies: any[]): any => {
88	  const policy = policies[step.policy];
89	  for (const damage of step.incident.damages) {
90	    if (damage.amount < 0) throw new Error("Negative damage amount");
91	  }
92	  const damageCounts: Record<string, number> = {};
93	  for (const damage of step.incident.damages) {
94	    damageCounts[damage.itemType] = (damageCounts[damage.itemType] ?? 0) + 1;
95	  }
96	  for (const [type, count] of Object.entries(damageCounts)) {
97	    const insuredCount = policy.items.filter((i: any) => i.type === type).length;
98	    if (count > insuredCount) throw new Error(`More damages of type ${type} than insured`);
99	  }
100	  let totalPayout = 0;
101	  for (const damage of step.incident.damages) {
102	    const item = policy.items.find((i: any) => i.type === damage.itemType);
103	    if (!item) throw new Error(`Item type ${damage.itemType} not in policy`);
104	    let reimbursement = damage.amount;
105	    if (item.enchantment >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
106	      reimbursement = damage.amount * HIGH_ENCHANTMENT_CLAIM_RATE;
107	    }
108	    const payout = reimbursement - DEDUCTIBLE;
109	    totalPayout += Math.max(0, payout);
110	  }
111	  totalPayout = Math.floor(Math.min(totalPayout, policy.remainingCap));
112	  policy.remainingCap -= totalPayout;
113	  return { payout: totalPayout, remainingCap: policy.remainingCap };
114	};
115	
116	export const processScenario = (scenario: any): any => {
117	  let quoteCount = 0;
118	  const policies: any[] = [];
119	  const results = scenario.steps.map((step: any) => {
120	    if (step.op === "quote") {
121	      const result = processQuote(step, scenario.customer.yearsWithMHPCO, quoteCount > 0, policies);
122	      quoteCount++;
123	      return result;
124	    }
125	    return processClaim(step, policies);
126	  });
127	  return { results };
128	};
